const body = $input.first().json.body || $input.first().json;
const stage = parseInt(body.stage);
const lead_id = body.lead_id;

if (!lead_id || isNaN(stage)) {
  throw new Error('Missing lead_id or stage in request body');
}

const stageFields = {
  1: { dm_sent_at: new Date().toISOString() },
  2: { dm_replied_at: new Date().toISOString() },
  3: { form_sent_at: new Date().toISOString() },
  4: { form_filled_at: new Date().toISOString() },
  5: { call_booked_at: new Date().toISOString() },
  6: { call_outcome: body.call_outcome || null },
  7: { call_outcome: 'closed' },
  8: { call_outcome: 'lost' },
};

const patch = {
  stage,
  stage_updated_at: new Date().toISOString(),
  ...(body.notes ? { notes: body.notes } : {}),
  ...(stageFields[stage] || {})
};

return [{ json: { lead_id, patch } }];
